const TIME_ZONE = 'America/New_York';
const DAILY_LIMIT = 300;
let MIN_BATCH_SIZE = 9;
let MAX_BATCH_SIZE = 18;
let MIN_EMAIL_DELAY_SECONDS = 8;
let MAX_EMAIL_DELAY_SECONDS = 25;
let MIN_BATCH_DELAY_MINUTES = 5;
let MAX_BATCH_DELAY_MINUTES = 7;
const FORCE_TEST_MODE = false;
const TEST_SUBJECT_PREFIX = '[N8N TEST]';
const TEST_DAILY_LIMIT = 2;
const TEST_MIN_BATCH_SIZE = 1;
const TEST_MAX_BATCH_SIZE = 2;
const TEST_DRAFT_SCAN_LIMIT = 100;

// Testing notes:
// - Set FORCE_TEST_MODE = true only during controlled testing.
// - Test drafts must have subjects that start with TEST_SUBJECT_PREFIX.
// - Confirm TEST_DAILY_LIMIT = 2 before a test run.
// - Confirm TEST_MIN_BATCH_SIZE = 1 and TEST_MAX_BATCH_SIZE = 2 before a test run.
// - Set FORCE_TEST_MODE back to false before real sending.
// - This workflow sends existing Gmail drafts through users.drafts.send and does not create, edit, or delete drafts manually.

const staticData = $getWorkflowStaticData('global');

function randomInt(min, max) {
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

function getEasternDateKey(date) {
  const parts = new Intl.DateTimeFormat('en-CA', {
    timeZone: TIME_ZONE,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  }).formatToParts(date);

  const values = Object.fromEntries(
    parts
      .filter((part) => part.type !== 'literal')
      .map((part) => [part.type, part.value]),
  );

  return `${values.year}-${values.month}-${values.day}`;
}

const todayKey = getEasternDateKey(new Date());

// Reset the daily counter automatically when the Eastern calendar date changes.
if (staticData.date !== todayKey) {
  staticData.date = todayKey;
  staticData.sentToday = 0;
}

const dailyLimit = FORCE_TEST_MODE ? TEST_DAILY_LIMIT : DAILY_LIMIT;
const minBatchSize = FORCE_TEST_MODE ? TEST_MIN_BATCH_SIZE : MIN_BATCH_SIZE;
const maxBatchSize = FORCE_TEST_MODE ? TEST_MAX_BATCH_SIZE : MAX_BATCH_SIZE;
const sentToday = Number(staticData.sentToday || 0);
const remainingToday = Math.max(dailyLimit - sentToday, 0);
const allowed = remainingToday > 0;
const batchSize = allowed ? Math.min(randomInt(minBatchSize, maxBatchSize), remainingToday) : 0;
const listMaxResults = FORCE_TEST_MODE ? TEST_DRAFT_SCAN_LIMIT : batchSize;

return [
  {
    json: {
      allowed,
      reason: allowed
        ? (FORCE_TEST_MODE ? 'FORCE_TEST_MODE_ACTIVE' : 'DAILY_LIMIT_AVAILABLE')
        : 'DAILY_LIMIT_REACHED',
      todayKey,
      dailyLimit,
      sentToday,
      remainingToday,
      batchSize,
      listMaxResults,
      minEmailDelaySeconds: MIN_EMAIL_DELAY_SECONDS,
      maxEmailDelaySeconds: MAX_EMAIL_DELAY_SECONDS,
      minBatchDelayMinutes: MIN_BATCH_DELAY_MINUTES,
      maxBatchDelayMinutes: MAX_BATCH_DELAY_MINUTES,
      forceTestMode: FORCE_TEST_MODE,
      testSubjectPrefix: TEST_SUBJECT_PREFIX,
    },
  },
];

const config = $('Check Daily Limit').item.json;
const drafts = Array.isArray($json.drafts) ? $json.drafts : [];
const draftsReturned = drafts.length;

if (draftsReturned === 0) {
  console.log('No Gmail drafts returned. Nothing to send.');
  return [];
}

// users.drafts.list returns draft IDs and message IDs only. Metadata is fetched next before any draft can be sent.
return drafts
  .filter((draft) => draft && draft.id)
  .map((draft) => ({
    json: {
      draftId: draft.id,
      messageId: draft.message?.id || null,
      batchSize: config.batchSize,
      listedDraftsReturned: draftsReturned,
      dailyLimit: config.dailyLimit,
      minEmailDelaySeconds: config.minEmailDelaySeconds,
      maxEmailDelaySeconds: config.maxEmailDelaySeconds,
      minBatchDelayMinutes: config.minBatchDelayMinutes,
      maxBatchDelayMinutes: config.maxBatchDelayMinutes,
      forceTestMode: config.forceTestMode,
      testSubjectPrefix: config.testSubjectPrefix,
    },
  }));

const config = $('Check Daily Limit').item.json;
const inputItems = $input.all();
const forceTestMode = Boolean(config.forceTestMode);
const testSubjectPrefix = config.testSubjectPrefix || '[N8N TEST]';
const batchSize = Number(config.batchSize || 0);

function getSubject(headers) {
  if (!Array.isArray(headers)) {
    return '';
  }

  const header = headers.find((entry) => String(entry.name || '').toLowerCase() === 'subject');
  return header?.value || '';
}

const candidates = inputItems.map((item) => {
  const draft = item.json;
  const subject = getSubject(draft.message?.payload?.headers);

  return {
    draftId: draft.id,
    messageId: draft.message?.id || null,
    subject,
  };
});

const eligibleDrafts = forceTestMode
  ? candidates.filter((draft) => draft.subject.startsWith(testSubjectPrefix))
  : candidates;

const selectedDrafts = eligibleDrafts.slice(0, batchSize);

if (forceTestMode) {
  const skipped = candidates
    .filter((draft) => !draft.subject.startsWith(testSubjectPrefix))
    .map((draft) => ({ draftId: draft.draftId, subject: draft.subject }));

  if (skipped.length > 0) {
    console.log(JSON.stringify({
      level: 'info',
      message: 'FORCE_TEST_MODE skipped drafts without the required subject prefix.',
      testSubjectPrefix,
      skipped,
    }));
  }

  if (selectedDrafts.length === 0) {
    console.log(JSON.stringify({
      level: 'info',
      message: 'FORCE_TEST_MODE found no drafts with the required subject prefix. Nothing will be sent.',
      testSubjectPrefix,
    }));
    return [];
  }
}

// In production mode, this node does not require the test prefix. In test mode, only matching subjects continue to Send Draft.
return selectedDrafts.map((draft) => ({
  json: {
    draftId: draft.draftId,
    messageId: draft.messageId,
    subject: draft.subject,
    batchSize,
    draftsReturned: selectedDrafts.length,
    listedDraftsReturned: candidates.length,
    eligibleDraftsReturned: eligibleDrafts.length,
    dailyLimit: config.dailyLimit,
    minEmailDelaySeconds: config.minEmailDelaySeconds,
    maxEmailDelaySeconds: config.maxEmailDelaySeconds,
    minBatchDelayMinutes: config.minBatchDelayMinutes,
    maxBatchDelayMinutes: config.maxBatchDelayMinutes,
    forceTestMode,
    testSubjectPrefix,
  },
}));

const draftItem = $('Loop Through Drafts').item.json;
const minDelay = Number(draftItem.minEmailDelaySeconds || 8);
const maxDelay = Number(draftItem.maxEmailDelaySeconds || 25);

function randomInt(min, max) {
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

// users.drafts.send has already sent the existing draft. This only chooses the pause before the next draft.
return [
  {
    json: {
      draftId: draftItem.draftId,
      subject: draftItem.subject,
      sentMessageId: $json.id || null,
      delaySeconds: randomInt(minDelay, maxDelay),
      minEmailDelaySeconds: minDelay,
      maxEmailDelaySeconds: maxDelay,
    },
  },
];

const TIME_ZONE = 'America/New_York';
const staticData = $getWorkflowStaticData('global');
const draftItem = $('Loop Through Drafts').item.json;

function getEasternDateKey(date) {
  const parts = new Intl.DateTimeFormat('en-CA', {
    timeZone: TIME_ZONE,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  }).formatToParts(date);

  const values = Object.fromEntries(
    parts
      .filter((part) => part.type !== 'literal')
      .map((part) => [part.type, part.value]),
  );

  return `${values.year}-${values.month}-${values.day}`;
}

const todayKey = getEasternDateKey(new Date());

// Count only confirmed successful sends, and reset if a long manual run crosses into a new Eastern date.
if (staticData.date !== todayKey) {
  staticData.date = todayKey;
  staticData.sentToday = 0;
}

staticData.sentToday = Number(staticData.sentToday || 0) + 1;

return [
  {
    json: {
      sentToday: staticData.sentToday,
      sentDraftId: draftItem.draftId,
      subject: draftItem.subject,
      timestamp: new Date().toISOString(),
      batchSize: draftItem.batchSize,
      draftsReturned: draftItem.draftsReturned,
      listedDraftsReturned: draftItem.listedDraftsReturned,
      eligibleDraftsReturned: draftItem.eligibleDraftsReturned,
      dailyLimit: draftItem.dailyLimit,
      minBatchDelayMinutes: draftItem.minBatchDelayMinutes,
      maxBatchDelayMinutes: draftItem.maxBatchDelayMinutes,
      forceTestMode: draftItem.forceTestMode,
      testSubjectPrefix: draftItem.testSubjectPrefix,
    },
  },
];

const TIME_ZONE = 'America/New_York';
const staticData = $getWorkflowStaticData('global');
const batchItems = $input.all().map((item) => item.json);
const firstBatchItem = batchItems[0] || {};
const config = $('Check Daily Limit').item.json;
const dailyLimit = Number(firstBatchItem.dailyLimit || config.dailyLimit || 300);
const draftsReturned = Number(firstBatchItem.draftsReturned || batchItems.length || 0);
const batchSize = Number(firstBatchItem.batchSize || draftsReturned || 0);
const minBatchDelayMinutes = Number(firstBatchItem.minBatchDelayMinutes || config.minBatchDelayMinutes || 5);
const maxBatchDelayMinutes = Number(firstBatchItem.maxBatchDelayMinutes || config.maxBatchDelayMinutes || 7);

function randomInt(min, max) {
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

function getEasternDateKey(date) {
  const parts = new Intl.DateTimeFormat('en-CA', {
    timeZone: TIME_ZONE,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  }).formatToParts(date);

  const values = Object.fromEntries(
    parts
      .filter((part) => part.type !== 'literal')
      .map((part) => [part.type, part.value]),
  );

  return `${values.year}-${values.month}-${values.day}`;
}

const todayKey = getEasternDateKey(new Date());

// Keep static data aligned with the Eastern calendar date during long manual runs.
if (staticData.date !== todayKey) {
  staticData.date = todayKey;
  staticData.sentToday = 0;
}

const sentToday = Number(staticData.sentToday || 0);
const remainingToday = Math.max(dailyLimit - sentToday, 0);
let continueSending = true;
let reason = 'CONTINUE_NEXT_BATCH';

if (sentToday >= dailyLimit) {
  continueSending = false;
  reason = 'DAILY_LIMIT_REACHED';
} else if (draftsReturned === 0 || draftsReturned < batchSize) {
  continueSending = false;
  reason = firstBatchItem.forceTestMode ? 'NO_MATCHING_TEST_DRAFTS_REMAINING' : 'NO_DRAFTS_REMAINING';
}

const batchDelayMinutes = continueSending ? randomInt(minBatchDelayMinutes, maxBatchDelayMinutes) : 0;

return [
  {
    json: {
      continueSending,
      reason,
      todayKey,
      dailyLimit,
      sentToday,
      remainingToday,
      draftsReturned,
      listedDraftsReturned: firstBatchItem.listedDraftsReturned || null,
      eligibleDraftsReturned: firstBatchItem.eligibleDraftsReturned || null,
      previousBatchSize: batchSize,
      batchDelayMinutes,
      minBatchDelayMinutes,
      maxBatchDelayMinutes,
    },
  },
];
